      // All three uploads were attempted — including the failing one — in order.
      expect(uploadedFileNames()).toEqual(['a.txt', 'b.txt', 'c.txt']);
      // The input is cleared even though one upload failed.
      expect(uploadInput.value).toBe('');
      // A re-render still happened after the upload loop.
      expect(browseCount()).toBeGreaterThan(browseBefore);
      // The failure is surfaced in the status footer: it names the failing
      // file and acknowledges the two files that did upload.
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('b.txt');
      expect(status.textContent).toMatch(/Uploaded\s+2/i);
      // Successful files are not flagged as failed.
      expect(status.textContent).not.toContain('c.txt');
      expect(status.textContent).not.toContain('a.txt');
    });

    it('continues uploading subsequent files when the first upload fails', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['bad.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['bad.txt', 'good.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['bad.txt', 'good.txt']);
      expect(uploadInput.value).toBe('');
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });

    it('clears the input, re-renders, and lists every failure when all uploads fail', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['x.txt', 'y.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['x.txt', 'y.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['x.txt', 'y.txt']);
      expect(uploadInput.value).toBe('');
      expect(browseCount()).toBeGreaterThan(browseBefore);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('x.txt');
      expect(status.textContent).toContain('y.txt');
    });

    it('does not surface a failure message when every upload succeeds (status stays the normal browse summary)', async () => {
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadInput.value).toBe('');
      // No failure report; renderBrowse's normal "N folders, M files, total S"
      // summary is what the re-render leaves behind.
      expect(status.textContent).not.toMatch(/failed/i);
      expect(status.textContent).toMatch(/folders.*files.*total/);
    });
  });

  describe('pickAndUploadInto (upload into an arbitrary folder)', () => {
    // Exercises pickAndUploadInto directly: it builds a transient
    // <input type=file multiple>, awaits its change/cancel, uploads every
    // chosen file into the GIVEN path (not the current route), then removes
    // the input and re-renders — mirroring handleUpload's contract but with a
    // caller-chosen destination.

    /** Grab the transient picker input that pickAndUploadInto appended to body. */
    function findPickerInput(): HTMLInputElement | undefined {
      // The transient input is a DIRECT child of <body>; the toolbar upload
      // input lives inside <label class="btn">, so its parent is not body.
      return Array.from(document.querySelectorAll('input[type=file]')).find(
        (i) => i.parentElement === document.body,
      ) as HTMLInputElement | undefined;
    }

    function setFiles(input: HTMLInputElement, names: string[]): void {
      const dt = new DataTransfer();
      for (const n of names) dt.items.add(new File(['data-' + n], n));
      input.files = dt.files as unknown as FileList;
    }

    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    function uploadCalls(): [string, RequestInit | undefined][] {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
    }

    it('creates a hidden <input type=file multiple> appended to body, then uploads each file into the given path', async () => {
      setup({ hash: toBrowseHash('current/dir') });
      await flush();

      // Suspend on the awaited picker: do NOT await yet.
      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      expect(pickInput, 'a transient picker input must be appended to body').toBeTruthy();
      expect(pickInput!.type).toBe('file');
      expect(pickInput!.multiple).toBe(true);

      setFiles(pickInput!, ['a.txt', 'b.txt']);
      pickInput!.dispatchEvent(new Event('change'));
      await p;
      await settle();

      // Uploads target the GIVEN path, NOT the current route.
      expect(uploadCalls()).toHaveLength(2);
      expect(
        uploadCalls().every(([u]) =>
          String(u).includes('path=' + encodeURIComponent('target/folder')),
        ),
      ).toBe(true);
      // The transient input was removed after the upload loop.
      expect(findPickerInput()).toBeUndefined();
    });

    it('uploads nothing and removes the input when the picker is cancelled (no files)', async () => {
      setup({ hash: toBrowseHash('docs') });
      await flush();

      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      expect(pickInput).toBeTruthy();

      // Dismiss the picker without choosing — the `cancel` event resolves
      // the awaited promise with an empty list.
      pickInput!.dispatchEvent(new Event('cancel'));
      await p;
      await settle();

      expect(uploadCalls()).toHaveLength(0);
      expect(findPickerInput()).toBeUndefined();
    });

    it('surfaces per-file failures in the status footer while still uploading the rest', async () => {
      fetchMock.mockImplementation(async (url: string, init?: RequestInit) => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && file.name === 'bad.txt') {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          return mockResponse({ body: browseResult({ path: 'target/folder', entries: [] }) });
        }
        return mockResponse({ status: 200, body: {} });
      });
      const { status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      setFiles(pickInput!, ['good.txt', 'bad.txt']);
      pickInput!.dispatchEvent(new Event('change'));
      await p;
      await settle();

      // Both were attempted; only bad.txt is flagged.
      expect(
        uploadCalls().map(([, init]) => ((init!.body as FormData).get('file') as File).name),
      ).toEqual(['good.txt', 'bad.txt']);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });
  });
});

/**
 * Shared test helpers for the `src/app/*.test.ts` per-domain test files.
 *
 * Extracted verbatim from the former `src/app.test.ts` monolith (split per
 * task-29) so each focused test file can import only what it needs. Houses:
 *
 *   - fixture builders: `fileEntry`, `browseResult`, `joinPathHelper`,
 *     `browseRoute`, `searchRoute`
 *   - timing: `flush`
 *   - DOM scaffolding: `setup`, `setupCleared`, `SetupCtx`
 *   - table/row traversal: `dataRows`, `rowByName`, `cellsOf`,
 *     `clickNameLink`, `buttonsByText`
 *   - the shared per-test fetch stub lifecycle: `installAppTestLifecycle` plus
 *     the `fetchMock` live binding it rebinds each test
 *
 * `browseRoute` / `searchRoute` construct `Route` fixtures. They were
 * referenced by the dead-CSS characterization suite in the monolith but never
 * defined (a latent bug that left those tests throwing `ReferenceError`); they
 * are defined here so those scenarios finally run. `renderBrowse` /
 * `renderSearch` no longer take a `route` argument (its removal is pinned by
 * the route-independence suite), so the value is ignored at runtime — but it
 * must be a defined expression rather than a bare `ReferenceError`.
 *
 * Test-only utility: deliberately kept out of the production `tsc` build via
 * the `src/app/test-helpers.ts` entry in `tsconfig.json`'s `exclude` array
 * (mirroring the `src/test-utils/**` glob added by task-27), so it is never
 * shipped to `wwwroot/dist`. Only test files import it.
 */
import { vi, beforeEach, afterEach } from 'vitest';
import { startApp } from '../app';
import type { BrowseResult, FileEntry, SearchResult } from '../api';
import type { Route } from '../router';
import { mockResponse } from '../test-utils/mock-response';

/* ===========================================================================
 * Constants & fixture builders
 * ========================================================================= */

export const ISO = '2024-03-15T10:30:00'; // offset-free → parsed as local time
export const ISO_FMT = '2024-03-15 10:30'; // expected formatDate(...) output

export function fileEntry(opts: Partial<FileEntry> & { name: string }): FileEntry {
  return {
    name: opts.name,
    path: opts.path ?? joinPathHelper('docs', opts.name),
    isDirectory: opts.isDirectory ?? false,
    size: opts.size ?? 0,
    lastModified: opts.lastModified ?? ISO,
  };
}

export function browseResult(opts: Partial<BrowseResult> = {}): BrowseResult {
  return {
    path: opts.path ?? '',
    parent: opts.parent ?? null,
    entries: opts.entries ?? [],
    folderCount: opts.folderCount ?? 0,
    fileCount: opts.fileCount ?? 0,
    totalSize: opts.totalSize ?? 0,
  };
}

// local join to avoid pulling joinPath into the test's asserted import set
export function joinPathHelper(base: string, name: string): string {
  return (base ? base + '/' : '') + name;
}

/** Build a browse `Route` fixture. */
export function browseRoute(path: string): Route {
  return { view: 'browse', path, query: '' };
}

/** Build a search `Route` fixture. */
export function searchRoute(query: string, path: string = ''): Route {
  return { view: 'search', query, path };
}

/* ===========================================================================
 * Timing
 * ========================================================================= */

/** Let pending microtasks / queued hashchange renders settle. */
export const flush = (): Promise<void> => new Promise((r) => setTimeout(r, 0));

/* ===========================================================================
 * DOM scaffolding
 * ========================================================================= */

export interface SetupCtx {
  root: HTMLElement;
  embeddedHost: HTMLElement;
  widget: HTMLElement;
  dialog: HTMLDialogElement;
  trigger: HTMLButtonElement;
  closeBtn: HTMLButtonElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  searchWrapper: HTMLElement;
  searchClearBtn: HTMLButtonElement;
  searchIcon: HTMLElement;
  uploadLabel: HTMLLabelElement;
  uploadInput: HTMLInputElement;
  results: HTMLElement;
  status: HTMLElement;
}

/**
 * Build a fresh app inside a fresh container. Clears `document.body` first so
 * every test is independent (no leakage of elements, and document-scoped
 * queries inside `renderBrowse`/`renderSearch` always resolve to the current
 * test's DOM).
 */
export function setup(options: { hash?: string } = {}): SetupCtx {
  document.body.innerHTML = '';
  window.location.hash = options.hash ?? '';

  const root = document.createElement('div');
  document.body.append(root);
  startApp(root);

  return {
    root,
    embeddedHost: root.querySelector('.file-browser-host') as HTMLElement,
    widget: root.querySelector('.file-browser') as HTMLElement,
    dialog: root.querySelector('dialog.browser-dialog') as HTMLDialogElement,
    trigger: root.querySelector('button.trigger') as HTMLButtonElement,
    closeBtn: root.querySelector('.close-btn') as HTMLButtonElement,
    breadcrumb: root.querySelector('.breadcrumb') as HTMLElement,
    searchInput: root.querySelector('input[type="text"]') as HTMLInputElement,
    searchWrapper: root.querySelector('.search-wrapper') as HTMLElement,
    searchClearBtn: root.querySelector('.search-wrapper .clear-btn') as HTMLButtonElement,
    searchIcon: root.querySelector('.search-wrapper .search-icon') as HTMLElement,
    uploadLabel: root.querySelector('label.btn') as HTMLLabelElement,
    uploadInput: root.querySelector('input[type="file"]') as HTMLInputElement,
    results: root.querySelector('.results') as HTMLElement,
    status: root.querySelector('.status') as HTMLElement,
  };
}

/**
 * `setup()` plus a flush (so startApp's initial `render()` settles) and a clear
 * of `.results`, mimicking what `render()` does before delegating to
 * `renderBrowse`/`renderSearch`. Used by tests that exercise those helpers
 * directly so their assertions are isolated from the initial render's output.
 */
export async function setupCleared(options: { hash?: string } = {}): Promise<SetupCtx> {
  const ctx = setup(options);
  await flush();
  ctx.results.innerHTML = '';
  return ctx;
}

/* ===========================================================================
 * Table-traversal helpers (browser-agnostic; work on Element).
 * ========================================================================= */

export function dataRows(table: Element): Element[] {
  return Array.from(table.querySelectorAll('tbody tr'));
}
export function rowByName(table: Element, name: string): Element | undefined {
  return dataRows(table).find((tr) => (tr.querySelector('td')?.textContent ?? '').trim() === name);
}
export function cellsOf(row: Element): Element[] {
  return Array.from(row.querySelectorAll('td'));
}
export function clickNameLink(row: Element): void {
  const nameCell = cellsOf(row)[0];
  const link = nameCell.querySelector('a, button') as HTMLElement | null;
  (link ?? (nameCell as HTMLElement)).click();
}
export function buttonsByText(container: Element, text: string): HTMLButtonElement[] {
  return Array.from(container.querySelectorAll('button')).filter(
    (b) => (b.textContent ?? '').trim() === text,
  );
}

/* ===========================================================================
 * Shared per-test fetch stub lifecycle
 *
 * `fetchMock` is an `export let` live binding: `installAppTestLifecycle()`'s
 * `beforeEach` rebinds it to a fresh permissive `vi.fn` each test, and every
 * importer sees the rebound value (ESM live bindings — verified against this
 * vitest setup). Tests therefore read `fetchMock.mock.calls` exactly as the
 * monolith did, with no per-file `let fetchMock` declaration.
 * ========================================================================= */

export let fetchMock: ReturnType<typeof vi.fn> = vi.fn(async () => mockResponse({ body: {} }));

/**
 * Register the shared `beforeEach` (permissive default fetch stub) and
 * `afterEach` (DOM + mock cleanup) used by every split app test file. Call
 * exactly once at module top level in each `*.test.ts`.
 */
export function installAppTestLifecycle(): void {
  beforeEach(() => {
    // A permissive default: every browse/search GET returns a recognizable
    // result derived from the requested path/query, and every mutation returns
    // 200. Individual tests override with `fetchMock.mockImplementation(...)`
    // or `.mockResolvedValueOnce(...)` for specific scenarios. This also means
    // incidental background renders (e.g. from accumulated hashchange
    // listeners) never throw unhandled rejections.
    fetchMock = vi.fn(async (url: string, init?: RequestInit) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/browse')) {
        const raw = u.split('path=')[1] ?? '';
        const path = decodeURIComponent(raw);
        const childName = 'child-of-' + (path || 'root');
        return mockResponse({
          body: browseResult({
            path,
            entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
            fileCount: 1,
            totalSize: 10,
          }),
        });
      }
      if (method === 'GET' && u.includes('/search')) {
        const afterQuery = u.slice(u.indexOf('query=') + 6);
        const query = decodeURIComponent(afterQuery.split('&')[0]);
        return mockResponse({
          body: {
            query,
            path: '',
            results: [
              fileEntry({
                name: 'result-for-' + query,
                path: joinPathHelper('docs', 'result-for-' + query),
              }),
            ],
          } as SearchResult,
        });
      }
      return mockResponse({ status: 200, body: {} });
    });
    vi.stubGlobal('fetch', fetchMock);
  });

  afterEach(() => {
    // NOTE: do NOT touch window.location.hash here. In happy-dom, assigning to
    // location.hash dispatches `hashchange` synchronously. startApp unsubscribes
    // the previous mount's render() listener on re-mount (so listeners no longer
    // accumulate across tests), but the CURRENT test's listener remains active
    // until the next test's setup() re-mounts. Resetting the hash after
    // `vi.unstubAllGlobals()` would therefore drive a render through the REAL
    // fetch. We clear the body first (while fetch is still stubbed, so any
    // in-flight render's already-issued request stays mocked) and reset the hash
    // at the start of the next test's setup() instead.
    document.body.innerHTML = '';
    vi.unstubAllGlobals();
    vi.restoreAllMocks();
  });
}

/**
 * Toolbar event handlers: search submission and file upload.
 *
 * Both operate against the shared DOM/API context (search input value, upload
 * input file list, current route) and trigger a re-render via the context's
 * render hook.
 */
import { getCurrentRoute, navigate, toBrowseHash, toSearchHash } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import { getApi, getSearchInput, getStatus, getUploadInput, rerender } from './context.js';

/**
 * Navigate to a search hash for the current input value and browse path.
 *
 * An empty (or whitespace-only) query clears the search instead: it navigates
 * to the browse route for the current path so the server never receives an
 * empty `query`, which it rejects with 400.
 */
export function doSearch(): void {
  const path = normalizeRelativePath(getCurrentRoute().path);
  const query = getSearchInput().value.trim();
  if (query === '') {
    navigate(toBrowseHash(path));
    return;
  }
  navigate(toSearchHash(query, path));
}

/**
 * Clear the search input and return to the browse view for the current path.
 *
 * Resets the search input value to an empty string, reads the current path
 * (normalised), and navigates to the browse hash for that path — the same
 * behaviour as {@link doSearch} when the query is empty, but exposed as an
 * explicit, unconditional entry point that also wipes the input text.
 */
export function clearSearch(): void {
  getSearchInput().value = '';
  const path = normalizeRelativePath(getCurrentRoute().path);
  navigate(toBrowseHash(path));
}

/**
 * Upload every selected file to the current path, handle per-file errors, then
 * clear the input, re-render the listing, and surface any failures in the
 * status footer.
 */
export async function handleUpload(): Promise<void> {
  const uploadInput = getUploadInput();
  const list = uploadInput.files;
  const files = list ? Array.from(list) : [];
  if (files.length === 0) {
    return;
  }
  const path = normalizeRelativePath(getCurrentRoute().path);
  const failed: string[] = [];
  for (const file of files) {
    try {
      await getApi().upload(path, file);
    } catch {
      failed.push(file.name);
    }
  }
  // Clear the input so selecting the same file again re-fires `change`.
  uploadInput.value = '';
  // Re-render the listing first so normal browse/search status is set.
  await rerender();
  // Surface failures after the normal render, so the message is not overwritten.
  if (failed.length > 0) {
    const succeeded = files.length - failed.length;
    getStatus().textContent = `Uploaded ${succeeded} file(s); failed: ${failed.join(', ')}`;
  }
}

/**
 * Open the native file picker and upload every selected file into `dirPath`
 * (an arbitrary directory, NOT necessarily the current route) — used by the
 * folder-row "Upload" and the current-directory context menus.
 *
 * This mirrors {@link handleUpload}'s per-file loop and failure surfacing but
 * uses a self-contained, transient `<input type="file" multiple>` instead of
 * the toolbar's shared upload input (whose `change` handler is hardwired to
 * the current route path). The transient input is appended hidden, clicked
 * (within the menu-item click's user gesture so the picker is allowed to
 * open), awaited until either `change` (files chosen) or `cancel` (dismissed),
 * then removed — so a cancel resolves cleanly with no upload and no leak.
 */
export async function pickAndUploadInto(dirPath: string): Promise<void> {
  const input = document.createElement('input');
  input.type = 'file';
  input.multiple = true;
  input.style.display = 'none';
  document.body.append(input);

  const files = await new Promise<File[]>((resolve) => {
    let settled = false;
    const finish = (list: File[]): void => {
      if (settled) {
        return;
      }
      settled = true;
      resolve(list);
    };
    input.addEventListener('change', () => {
      finish(input.files ? Array.from(input.files) : []);
    });
    // `cancel` fires when the user dismisses the picker without choosing —
    // resolve with an empty list so the input is removed and no upload runs.
    input.addEventListener('cancel', () => finish([]));
    input.click();
  });
  input.remove();

  if (files.length === 0) {
    return;
  }
  const path = normalizeRelativePath(dirPath);
  const failed: string[] = [];
  for (const file of files) {
    try {
      await getApi().upload(path, file);
    } catch {
      failed.push(file.name);
    }
  }
  await rerender();
  if (failed.length > 0) {
    const succeeded = files.length - failed.length;
    getStatus().textContent = `Uploaded ${succeeded} file(s); failed: ${failed.join(', ')}`;
  }
}

/**
 * Tests for the search-wrapper DOM restructuring and event rewiring that
 * `src/app.ts`'s `startApp` performs:
 *
 *   - The legacy "Search" `<button>` is removed entirely.
 *   - A `.search-wrapper` div wraps the search `<input>`, a leading search
 *     icon (`bi bi-search search-icon`), and a trailing clear button
 *     (`.clear-btn` containing a `bi bi-x-lg` icon).
 *   - The clear button is an icon-only `<button type="button">` carrying
 *     `aria-label="Clear search"`.
 *   - Child order inside the wrapper is exactly input → search-icon →
 *     clear-btn (the CSS visibility rule for the clear button uses the
 *     general sibling `~` combinator against the input's `:placeholder-shown`).
 *   - `input` events are debounced (200 ms) before triggering `doSearch`;
 *     each new keystroke resets the timer so only the final value searches.
 *   - `Enter` triggers search immediately (no debounce, no stopPropagation).
 *   - `Escape` clears the search AND calls `event.stopPropagation()` so an
 *     enclosing `<dialog>` is not dismissed by the native ESC-to-close
 *     behavior.
 *   - Clicking the clear button invokes `clearSearch`.
 *   - The `DomRefs` passed to `init()` are unchanged: exactly the 5 standard
 *     refs (`results`, `status`, `breadcrumb`, `searchInput`, `uploadInput`)
 *     — the wrapper and clear button are NOT added, because clear-button
 *     visibility is driven purely by CSS (`:placeholder-shown`).
 *
 * The shared `init` from `./render-orchestrator` is wrapped in a pass-through
 * spy (via `vi.mock`) so the DomRefs suite can assert on the exact argument
 * `startApp` passes. The spy delegates to the real `init`, so the app still
 * mounts and renders normally in every other suite here.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { init } from './render-orchestrator';
import { toBrowseHash, toSearchHash } from '../router';
import { setup, flush, installAppTestLifecycle } from './test-helpers';

// Wrap `init` in a pass-through spy so the DomRefs suite can inspect the exact
// refs object startApp hands to init. The spy calls the real init, so the app
// still binds refs, subscribes hashchange, and kicks off the initial render.
vi.mock('./render-orchestrator', async (importOriginal) => {
  const actual = await importOriginal<typeof import('./render-orchestrator')>();
  return { ...actual, init: vi.fn(actual.init) };
});

installAppTestLifecycle();

// Clear the init spy's call history before each test so call counts reflect
// only the current test's startApp mount. (mockClear, not mockReset: we must
// keep the delegation to the real init.)
beforeEach(() => {
  vi.mocked(init).mockClear();
});

/**
 * Build a fresh app and resolve the search-wrapper sub-elements directly from
 * the rendered DOM.
 *
 * `test-helpers.ts`'s `SetupCtx` now exposes `searchWrapper` /
 * `searchClearBtn` / `searchIcon` (the legacy standalone `searchBtn` field was
 * removed once the search button was dropped from the DOM). This local helper
 * keeps resolving those nodes plus the `.toolbar` handle per-test so the
 * assertions here stay coupled to the rendered DOM rather than to the shared
 * context's field set.
 */
function setupSearchWrapper(options: { hash?: string } = {}) {
  const ctx = setup(options);
  const toolbar = ctx.root.querySelector('.toolbar') as HTMLElement;
  const searchWrapper = ctx.root.querySelector('.search-wrapper') as HTMLElement;
  const searchIcon = searchWrapper.querySelector('.search-icon') as HTMLElement;
  const searchClearBtn = searchWrapper.querySelector('.clear-btn') as HTMLButtonElement;
  return { ...ctx, toolbar, searchWrapper, searchIcon, searchClearBtn };
}

/* ===========================================================================
 * Structure: the "Search" button is gone; a .search-wrapper holds the icons
 * ========================================================================= */
describe('startApp search area structure', () => {
  describe('the legacy "Search" button is removed', () => {
    it('renders no button whose trimmed text content is "Search"', () => {
      const { root } = setup();
      const searchButtons = Array.from(root.querySelectorAll('button')).filter(
        (b) => (b.textContent ?? '').trim() === 'Search',
      );
      expect(searchButtons).toHaveLength(0);
    });

    it('the toolbar has exactly one .btn element — the Upload label', () => {
      // The old search button carried the `btn` class; with it gone, the only
      // `.btn` left in the toolbar is the upload label.
      const { toolbar } = setupSearchWrapper();
      const btns = Array.from(toolbar.querySelectorAll('.btn'));
      expect(btns).toHaveLength(1);
      expect(btns[0].tagName).toBe('LABEL');
      expect((btns[0].textContent ?? '').trim()).toBe('Upload');
    });
  });

  describe('.search-wrapper', () => {
    it('creates a div.search-wrapper inside the toolbar', () => {
      const { toolbar, searchWrapper } = setupSearchWrapper();
      expect(searchWrapper).toBeTruthy();
      expect(searchWrapper.tagName).toBe('DIV');
      expect(searchWrapper.className).toBe('search-wrapper');
      expect(toolbar.contains(searchWrapper)).toBe(true);
    });

    it('places search-wrapper between the breadcrumb and the upload label', () => {
      const { toolbar } = setupSearchWrapper();
      const children = Array.from(toolbar.children);
      expect(children).toHaveLength(3);
      expect(children[0].className).toBe('breadcrumb');
      expect(children[1].className).toBe('search-wrapper');
      expect(children[2].className).toBe('btn'); // upload label
    });

    it('contains the search text input with the "Search..." placeholder', () => {
      const { searchWrapper, searchInput } = setupSearchWrapper();
      expect(searchInput).toBeTruthy();
      expect(searchInput.type).toBe('text');
      expect(searchInput.getAttribute('placeholder')).toBe('Search...');
      expect(searchWrapper.contains(searchInput)).toBe(true);
    });

    it('contains a search icon <i> with classes "bi bi-search search-icon"', () => {
      const { searchWrapper, searchIcon } = setupSearchWrapper();
      expect(searchIcon).toBeTruthy();
      expect(searchIcon.tagName).toBe('I');
      expect(searchIcon.className).toBe('bi bi-search search-icon');
      expect(searchWrapper.contains(searchIcon)).toBe(true);
    });

    it('contains a clear button.clear-btn of type button', () => {
      const { searchWrapper, searchClearBtn } = setupSearchWrapper();
      expect(searchClearBtn).toBeTruthy();
      expect(searchClearBtn.tagName).toBe('BUTTON');
      expect(searchClearBtn.className).toBe('clear-btn');
      expect(searchClearBtn.type).toBe('button');
      expect(searchWrapper.contains(searchClearBtn)).toBe(true);
    });

    it('the clear button carries aria-label="Clear search"', () => {
      // Icon-only button: it has no visible text, so the accessible name must
      // come from aria-label.
      const { searchClearBtn } = setupSearchWrapper();
      expect(searchClearBtn.getAttribute('aria-label')).toBe('Clear search');
    });

    it('the clear button is icon-only (empty trimmed text content)', () => {
      const { searchClearBtn } = setupSearchWrapper();
      expect((searchClearBtn.textContent ?? '').trim()).toBe('');
    });

    it('the clear button contains an <i> icon with classes "bi bi-x-lg"', () => {
      const { searchClearBtn } = setupSearchWrapper();
      const icon = searchClearBtn.querySelector('i');
      expect(icon).toBeTruthy();
      expect(icon?.className).toBe('bi bi-x-lg');
    });

    it('orders children exactly: input → search-icon → clear-btn', () => {
      // ORDER MATTERS: the CSS rule that shows/hides the clear button relies
      // on the general-sibling (~) combinator against the input's
      // :placeholder-shown state, so the input must precede the clear button.
      const { searchWrapper, searchInput, searchIcon, searchClearBtn } = setupSearchWrapper();
      const children = Array.from(searchWrapper.children);
      expect(children).toHaveLength(3);
      expect(children[0]).toBe(searchInput);
      expect(children[1]).toBe(searchIcon);
      expect(children[2]).toBe(searchClearBtn);
    });

    it('the clear button is the only button inside the wrapper', () => {
      const { searchWrapper } = setupSearchWrapper();
      const buttons = searchWrapper.querySelectorAll('button');
      expect(buttons).toHaveLength(1);
    });
  });
});

/* ===========================================================================
 * Event wiring: debounce, Enter, Escape, clear-button click
 * ========================================================================= */
describe('startApp search area events', () => {
  describe('debounced input listener (200 ms)', () => {
    // Fake timers are engaged AFTER the real-timer `await flush()` so the
    // initial render (started by setup → startApp → init → render) can settle
    // using real microtask/timer scheduling. The debounce timer is created
    // only when an `input` event is dispatched below, i.e. after the switch.
    afterEach(() => {
      vi.useRealTimers();
    });

    it('does not search synchronously when the input changes', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'hello';
      searchInput.dispatchEvent(new Event('input'));

      // Synchronously after the input event: still browsing.
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('fires doSearch once 200 ms have elapsed since the last keystroke', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'hello';
      searchInput.dispatchEvent(new Event('input'));

      vi.advanceTimersByTime(199);
      expect(window.location.hash).toBe(toBrowseHash('docs')); // not yet

      vi.advanceTimersByTime(1); // 200 ms total
      expect(window.location.hash).toBe(toSearchHash('hello', 'docs'));
    });

    it('resets the debounce window on each keystroke (only the last value searches)', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'a';
      searchInput.dispatchEvent(new Event('input'));
      vi.advanceTimersByTime(150); // first timer has 50 ms left

      searchInput.value = 'ab';
      searchInput.dispatchEvent(new Event('input')); // cancels first, starts fresh
      vi.advanceTimersByTime(150); // 150 ms since last keystroke — still inside
      expect(window.location.hash).toBe(toBrowseHash('docs'));

      vi.advanceTimersByTime(50); // 200 ms since last keystroke
      expect(window.location.hash).toBe(toSearchHash('ab', 'docs'));
    });

    it('trims the query before navigating to the search hash', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = '   spaced   ';
      searchInput.dispatchEvent(new Event('input'));

      vi.advanceTimersByTime(200);
      expect(window.location.hash).toBe(toSearchHash('spaced', 'docs'));
    });

    it('a second debounce can fire after the first one completes', async () => {
      // Guards against a regression where the timer variable is not reset to
      // null after firing, which would block subsequent searches.
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'a';
      searchInput.dispatchEvent(new Event('input'));
      vi.advanceTimersByTime(200); // first search fires
      expect(window.location.hash).toBe(toSearchHash('a', 'docs'));

      searchInput.value = 'ab';
      searchInput.dispatchEvent(new Event('input'));
      vi.advanceTimersByTime(199);
      expect(window.location.hash).toBe(toSearchHash('a', 'docs')); // not yet
      vi.advanceTimersByTime(1);
      expect(window.location.hash).toBe(toSearchHash('ab', 'docs'));
    });
  });

  describe('Enter key (immediate search, no debounce)', () => {
    it('triggers search immediately on Enter (no 200 ms wait)', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'foo';
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter' }));

      expect(window.location.hash).toBe(toSearchHash('foo', 'docs'));
    });

    it('does not stop propagation on Enter', () => {
      // Only Escape stops propagation; Enter must not, so it cannot interfere
      // with any upstream keydown handling.
      const { searchInput } = setupSearchWrapper();
      const event = new KeyboardEvent('keydown', { key: 'Enter' });
      const stopSpy = vi.spyOn(event, 'stopPropagation');

      searchInput.dispatchEvent(event);

      expect(stopSpy).not.toHaveBeenCalled();
    });
  });

  describe('Escape key (clear + stopPropagation)', () => {
    it('clears the search input value on Escape', () => {
      const { searchInput } = setupSearchWrapper({ hash: toSearchHash('foo', 'docs') });
      searchInput.value = 'foo';

      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));

      expect(searchInput.value).toBe('');
    });

    it('navigates back to the browse view for the current path on Escape', () => {
      setupSearchWrapper({ hash: toSearchHash('foo', 'docs') });

      const searchInput = document.querySelector('.search-wrapper input[type="text"]')!;
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('stops propagation on Escape (so an enclosing dialog is not dismissed)', () => {
      // The search input may live inside a <dialog> (when the browser modal is
      // open). Without stopPropagation, the native dialog ESC-to-close behavior
      // would fire and dismiss the dialog. The handler must swallow the Escape
      // so it only clears the search.
      const { searchInput } = setupSearchWrapper();
      const event = new KeyboardEvent('keydown', { key: 'Escape' });
      const stopSpy = vi.spyOn(event, 'stopPropagation');

      searchInput.dispatchEvent(event);

      expect(stopSpy).toHaveBeenCalled();
    });

    it('clears before stopPropagation order does not matter (both effects occur)', () => {
      const { searchInput } = setupSearchWrapper({ hash: toSearchHash('bar', 'docs') });
      searchInput.value = 'bar';
      const event = new KeyboardEvent('keydown', { key: 'Escape' });
      vi.spyOn(event, 'stopPropagation');

      searchInput.dispatchEvent(event);

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });
  });

  describe('clear button click', () => {
    it('clears the search input value when the clear button is clicked', () => {
      const { searchClearBtn, searchInput } = setupSearchWrapper({
        hash: toSearchHash('foo', 'docs'),
      });
      searchInput.value = 'foo';

      searchClearBtn.click();

      expect(searchInput.value).toBe('');
    });

    it('navigates back to the browse view for the current path on clear click', () => {
      const { searchClearBtn } = setupSearchWrapper({ hash: toSearchHash('foo', 'docs') });

      searchClearBtn.click();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });
  });
});

/* ===========================================================================
 * DomRefs: init receives exactly the 5 standard refs
 *
 * The clear-button visibility is driven purely by CSS (:placeholder-shown on
 * the input), so startApp must NOT add searchWrapper or searchClearBtn to the
 * refs object it hands to init. Pinning the exact key set guards against a
 * regression that threads the new nodes through the shared context.
 * ========================================================================= */
describe('startApp search area: DomRefs unchanged', () => {
  it('passes exactly the 5 standard refs to init (no searchWrapper / clearBtn)', () => {
    const { searchInput, uploadInput, results, status, breadcrumb } = setupSearchWrapper();

    expect(init).toHaveBeenCalledTimes(1);
    const refs = vi.mocked(init).mock.calls[0][0];
    expect(Object.keys(refs).sort()).toEqual([
      'breadcrumb',
      'results',
      'searchInput',
      'status',
      'uploadInput',
    ]);
    // The refs point at the actual rendered nodes (not clones/duplicates).
    expect(refs.results).toBe(results);
    expect(refs.status).toBe(status);
    expect(refs.breadcrumb).toBe(breadcrumb);
    expect(refs.searchInput).toBe(searchInput);
    expect(refs.uploadInput).toBe(uploadInput);
  });

  it('does not attach a separate clear-button listener via the context (no getSearchClearBtn)', async () => {
    // The context module exposes getters only for the 5 standard refs. The
    // clear-button click handler is wired directly in startApp (imperative
    // addEventListener), not through a context ref — so importing the context
    // must not surface a clear-button getter. This is a structural guard: if a
    // future change adds the clear button to DomRefs, a matching getter would
    // appear here.
    const ctx = await import('./context');
    expect(typeof (ctx as Record<string, unknown>).getSearchClearBtn).toBe('undefined');
    expect(typeof (ctx as Record<string, unknown>).getSearchWrapper).toBe('undefined');
  });
});

/**
 * SPA entry — wires `api`, `router`, and the DOM into a file-browser UI
 * rendered inside a native `<dialog>` widget.
 *
 * This module is the thin entry point: it builds the DOM imperatively, wires
 * toolbar/dialog events, binds the resulting element refs into the render
 * orchestrator (which owns the route dispatch and render lifecycle), and kicks
 * off the initial render. The rendering logic itself lives in the focused
 * modules under `./app/`:
 *
 *   - `./app/context.js`             — shared API client, DOM refs, render hook
 *   - `./app/dom-builders.js`        — table/breadcrumb/row/action-button builders
 *   - `./app/render-browse.js`       — browse-result rendering
 *   - `./app/render-search.js`       — search-result rendering
 *   - `./app/toolbar-handlers.js`    — search + upload handlers
 *   - `./app/render-orchestrator.js` — route dispatch + render lifecycle
 *
 * Structure (built imperatively via `document.createElement`):
 *
 *   .file-browser-host   — primary chromeless surface; hosts the widget while
 *                          the dialog is closed (embedded view)
 *   <button class="trigger">Browse Files</button>
 *   <dialog class="browser-dialog">  — frame + titlebar (dialog-only chrome)
 *     .dialog-header     — title <span> + Close icon <button>
 *     .dialog-body        — empty slot; the shared widget moves here on open
 *
 *   The shared .file-browser widget (toolbar + .results + .status) is MOVED
 *   between the embedded host and the dialog body as the dialog opens/closes.
 *   It carries no border/background/title of its own — only the dialog adds
 *   the frame + titlebar, so the embedded view is chromeless.
 *
 *   .file-browser:
 *     toolbar   — .breadcrumb + .search-wrapper (search <input> +
 *                search-icon + clear-btn) + <label> upload
 *     .results  — file/folder <table>
 *     <footer class="status"> — summary line
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 *
 * `renderBrowse` and `renderSearch` are re-exported so `src/app.test.ts`'s
 * existing `import { startApp, renderBrowse, renderSearch } from './app'`
 * continues to resolve without modification.
 */
import { doSearch, handleUpload, clearSearch } from './app/toolbar-handlers.js';
import { init } from './app/render-orchestrator.js';
import type { DomRefs } from './app/context.js';

export { renderBrowse } from './app/render-browse.js';
export { renderSearch } from './app/render-search.js';

/* =========================================================================
 * startApp — build the DOM, wire events, bind refs, kick off rendering
 * ========================================================================= */

export function startApp(root: HTMLElement): void {
  root.innerHTML = '';

  /* --- File-browser widget (chromeless; shared by the embedded view and the
     dialog). It owns the toolbar, results, and status. The frame and titlebar
     belong to whichever host renders it — never to the widget itself — so when
     it is embedded directly in the page it carries no border/background/title. --- */
  const widget = document.createElement('div');
  widget.className = 'file-browser';

  // Toolbar: breadcrumb, search, upload
  const toolbar = document.createElement('div');
  toolbar.className = 'toolbar';
  const breadcrumbEl = document.createElement('div');
  breadcrumbEl.className = 'breadcrumb';
  const searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.placeholder = 'Search...';
  // Search affordance: a wrapper holding the input, a leading search icon,
  // and a trailing clear button (the latter toggled purely by CSS via
  // `:placeholder-shown`, so it needs no ref in DomRefs).
  const searchWrapper = document.createElement('div');
  searchWrapper.className = 'search-wrapper';
  const searchIcon = document.createElement('i');
  searchIcon.className = 'bi bi-search search-icon';
  const searchClearBtn = document.createElement('button');
  searchClearBtn.className = 'clear-btn';
  searchClearBtn.type = 'button';
  searchClearBtn.setAttribute('aria-label', 'Clear search');
  const clearIcon = document.createElement('i');
  clearIcon.className = 'bi bi-x-lg';
  searchClearBtn.append(clearIcon);
  // ORDER MATTERS: input first, then icon, then clear-btn (CSS uses ~ sibling combinator)
  searchWrapper.append(searchInput, searchIcon, searchClearBtn);
  const uploadLabel = document.createElement('label');
  uploadLabel.className = 'btn';
  uploadLabel.textContent = 'Upload';
  const uploadInput = document.createElement('input');
  uploadInput.type = 'file';
  uploadInput.multiple = true;
  // Visually hidden via the sr-only clip pattern (the `visually-hidden`
  // class) rather than the `hidden` HTML attribute: the attribute's UA
  // `display:none` ejects the control from the tab order, leaving Upload
  // unreachable via keyboard (WCAG 2.1.1). The class clips it to a 1x1 box
  // so it stays focusable; the visible "Upload" affordance is this wrapping
  // label.btn, and `.toolbar label.btn:focus-within` reflects focus onto it.
  uploadInput.classList.add('visually-hidden');
  // The input is now the element Tab lands on, so it needs its own accessible
  // name (the label text alone doesn't name a focusable input reliably).
  uploadInput.setAttribute('aria-label', 'Upload files');
  uploadLabel.append(uploadInput);
  toolbar.append(breadcrumbEl, searchWrapper, uploadLabel);

  // Results container + status footer
  const resultsEl = document.createElement('div');
  resultsEl.className = 'results';
  const statusEl = document.createElement('footer');
  statusEl.className = 'status';

  widget.append(toolbar, resultsEl, statusEl);

  /* --- Embedded host: the primary, chromeless surface. The widget lives here
     while the dialog is closed. --- */
  const embeddedHost = document.createElement('div');
  embeddedHost.className = 'file-browser-host';
  embeddedHost.append(widget);

  /* --- Trigger button --- */
  const trigger = document.createElement('button');
  trigger.className = 'trigger';
  trigger.textContent = 'Browse Files';

  /* --- Native <dialog>: supplies the frame (border/background) and titlebar
     (title + close). Its body is an empty slot the shared widget drops into
     when opened. --- */
  const dialog = document.createElement('dialog');
  dialog.className = 'browser-dialog';

  // Titlebar: centered title + Close (icon) button
  const header = document.createElement('div');
  header.className = 'dialog-header';
  const titleSpan = document.createElement('span');
  titleSpan.className = 'title';
  titleSpan.textContent = 'File Browser';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'close-btn';
  closeBtn.type = 'button';
  // Icon button has no visible text, so expose an accessible name.
  closeBtn.setAttribute('aria-label', 'Close');
  const closeIcon = document.createElement('i');
  closeIcon.className = 'bi bi-x-lg';
  closeBtn.append(closeIcon);
  header.append(titleSpan, closeBtn);

  // Dialog body slot: the widget is moved here on open, back to the host on close.
  const dialogBody = document.createElement('div');
  dialogBody.className = 'dialog-body';

  dialog.append(header, dialogBody);
  root.append(embeddedHost, trigger, dialog);

  /* --- Event wiring --- */
  // Opening the dialog MOVES the shared widget into the dialog body (reusing
  // the same nodes, so the context refs and any in-flight render stay valid),
  // then shows it. Closing — via the close button, ESC, etc. — fires the
  // dialog's `close` event, which moves the widget back to the embedded host.
  trigger.addEventListener('click', () => {
    dialogBody.append(widget);
    dialog.showModal();
  });
  dialog.addEventListener('close', () => {
    embeddedHost.append(widget);
  });
  closeBtn.addEventListener('click', () => dialog.close());

  // Debounced search: re-fire `doSearch` 200ms after the last keystroke so
  // typing a query doesn't pound the API on every character.
  let searchDebounceTimer: ReturnType<typeof setTimeout> | null = null;
  searchInput.addEventListener('input', () => {
    if (searchDebounceTimer !== null) {
      clearTimeout(searchDebounceTimer);
    }
    searchDebounceTimer = setTimeout(() => {
      searchDebounceTimer = null;
      doSearch();
    }, 200);
  });
  // Clear button: wipe the input and return to the browse view.
  searchClearBtn.addEventListener('click', clearSearch);
  searchInput.addEventListener('keydown', (event: KeyboardEvent) => {
    if (event.key === 'Enter') {
      doSearch();
    } else if (event.key === 'Escape') {
      // stopPropagation is critical: when the widget lives inside the open
      // <dialog>, the native ESC-to-close would otherwise dismiss the dialog.
      event.stopPropagation();
      clearSearch();
    }
  });

  uploadInput.addEventListener('change', handleUpload);

  /* --- Bind refs into the orchestrator + context, subscribe, and kick off
     the initial render. --- */
  const refs: DomRefs = {
    results: resultsEl,
    status: statusEl,
    breadcrumb: breadcrumbEl,
    searchInput,
    uploadInput,
  };
  init(refs);
}

/* =========================================================================
 * Bootstrap
 *
 * Guarded so the module is importable in tests (which have no #app element)
 * without side effects. Only mounts when a real #app container exists.
 * ========================================================================= */

const appRoot = document.getElementById('app');
if (appRoot) {
  startApp(appRoot);
}

/**
 * Route dispatcher and rendering-lifecycle owner.
 *
 * `render` reads the current route, fetches the matching result from the API,
 * and delegates to `renderBrowse` / `renderSearch`. It guards against render
 * races (a slower, superseded fetch cannot clobber fresher results) via a
 * monotonic token checked after each `await`.
 *
 * `init` is called once per `startApp` mount: it binds the freshly-built DOM
 * refs into the shared context, registers `render` as the re-render hook (so
 * action buttons and uploads can trigger it without a circular import), tears
 * down any previous mount's hashchange listener, subscribes a new one, and
 * kicks off the initial render.
 */
import { getCurrentRoute, subscribe } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import { getApi, getResults, setRefs, setRenderHook, type DomRefs } from './context.js';
import { renderBrowse } from './render-browse.js';
import { renderSearch } from './render-search.js';

/* -------------------------------------------------------------------------
 * Rendering-lifecycle state
 *
 * `unsubscribe` holds the teardown for the CURRENT mount's hashchange listener.
 * `init` clears any previous listener before subscribing a new one, so a
 * re-mount never leaves the old listener on `window` (memory leak fix).
 *
 * `renderToken` is a monotonic counter incremented at the start of every
 * `render()`. Each in-flight render captures its token and, after each `await`,
 * bails out if a newer render has started — preventing a slower, superseded
 * fetch from clobbering the freshest results (render-race fix).
 * ---------------------------------------------------------------------- */
let unsubscribe: (() => void) | null = null;
let renderToken = 0;

/**
 * Bind the freshly-built DOM refs into the shared context, register `render`
 * as the re-render hook, tear down any previous mount's hashchange listener,
 * subscribe a new one, and kick off the initial render.
 */
export function init(refs: DomRefs): void {
  setRefs(refs);
  setRenderHook(render);
  // Tear down the previous mount's listener first (if any) so re-mounts never
  // accumulate hashchange listeners on `window`.
  if (unsubscribe !== null) {
    unsubscribe();
    unsubscribe = null;
  }
  unsubscribe = subscribe(render);
  render();
}

/**
 * Route dispatcher.
 *
 * Clears the results container synchronously (so a pending/failed fetch never
 * leaves a stale table behind) but does NOT clear the breadcrumb or status
 * here. Clearing those synchronously would remove in-page navigation targets
 * in the middle of a click handler: `navigate()` dispatches `hashchange`
 * synchronously in happy-dom, which would re-enter `render` and wipe the
 * breadcrumb before the click's caller can read the next segment. The
 * breadcrumb/status are instead refreshed by `renderBrowse`/`renderSearch`
 * once data arrives.
 */
export async function render(): Promise<void> {
  // Claim this render slot. A newer render increments `renderToken` past
  // `myToken`; after each `await` we bail out if superseded so a slower fetch
  // can never overwrite the freshest results, breadcrumb, or status.
  const myToken = ++renderToken;
  const route = getCurrentRoute();
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  // Show a spinner in the results container while a search fetch is in flight.
  // For browse routes, no spinner is shown. The spinner is removed naturally:
  // `renderSearch(result)` clears the container before building the table, and
  // the error handler's `textContent` assignment replaces all content.
  if (route.view === 'search') {
    const spinnerWrap = document.createElement('div');
    spinnerWrap.className = 'search-spinner';
    const spinnerIcon = document.createElement('i');
    spinnerIcon.className = 'bi bi-arrow-repeat spinning';
    spinnerWrap.appendChild(spinnerIcon);
    resultsEl.appendChild(spinnerWrap);
  }
  try {
    if (route.view === 'browse') {
      const result = await getApi().browse(normalizeRelativePath(route.path));
      if (myToken !== renderToken) return;
      renderBrowse(result);
    } else {
      const result = await getApi().search(route.query, normalizeRelativePath(route.path));
      if (myToken !== renderToken) return;
      renderSearch(result);
    }
  } catch (err) {
    // A superseded render must not even commit its error.
    if (myToken !== renderToken) return;
    // textContent replaces all children, so any stale table is removed too.
    resultsEl.textContent =
      err instanceof Error ? 'Error: ' + err.message : 'Error: ' + String(err);
  }
}

/**
 * Builds a minimal fetch `Response` stand-in for the mocked global `fetch`.
 *
 * `text()` returns the raw text (defaults to the JSON-stringified body).
 * `json()` returns the parsed body when one is provided; otherwise it falls
 * back to parsing `text` as JSON (when only `text` was given), and finally to
 * an empty object. `ok` is derived from `status` (true for any 2xx) unless an
 * explicit `ok` is supplied, in which case it wins.
 *
 * This is the UNION of the two previously-inline helpers that lived in
 * `src/api.test.ts` and `src/app.test.ts`. They were identical except in the
 * `json()` fallback for the text-only case: the `app` copy returned `{}`,
 * whereas the `api` copy parsed the text as JSON. Parsing is the more
 * permissive behavior (a strict superset) and is preserved here so every
 * existing call site keeps working. (No call site actually relies on this
 * branch: on the error path `ApiClient.request` only reads `.text()`, and on
 * the success path a `body` is always supplied.) The behavior is pinned by the
 * `mockResponse helper` characterization suite in `src/api.test.ts`.
 *
 * Test-only utility: deliberately kept out of the production `tsc` build via
 * the `src/test-utils/**` glob in `tsconfig.json`'s `exclude` array, so it is
 * never shipped to `wwwroot/dist`. Only test files import it.
 */
export interface MockResponseOptions {
  ok?: boolean;
  status?: number;
  body?: unknown;
  text?: string;
}

export function mockResponse(opts: MockResponseOptions): Response {
  const status = opts.status ?? 200;
  const ok = opts.ok ?? (status >= 200 && status < 300);
  const text = opts.text ?? JSON.stringify(opts.body ?? {});
  return {
    ok,
    status,
    text: async () => text,
    json: async () => opts.body ?? (opts.text ? JSON.parse(opts.text) : {}),
  } as unknown as Response;
}

export interface FileEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  size: number;
  lastModified: string;
}

export interface BrowseResult {
  path: string;
  parent: string | null;
  entries: FileEntry[];
  folderCount: number;
  fileCount: number;
  totalSize: number;
}

export interface SearchResult {
  query: string;
  path: string;
  results: FileEntry[];
}

export class ApiClient {
  constructor(private readonly baseUrl: string = '/api/files') {}

  async browse(path: string): Promise<BrowseResult> {
    return this.request<BrowseResult>(`${this.baseUrl}/browse?path=${encodeURIComponent(path)}`, {
      method: 'GET',
    });
  }

  async search(query: string, path: string): Promise<SearchResult> {
    return this.request<SearchResult>(
      `${this.baseUrl}/search?query=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`,
      { method: 'GET' },
    );
  }

  async upload(path: string, file: File): Promise<{ path: string }> {
    const formData = new FormData();
    formData.append('file', file);
    return this.request<{ path: string }>(
      `${this.baseUrl}/upload?path=${encodeURIComponent(path)}`,
      { method: 'POST', body: formData },
    );
  }

  async delete(path: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/delete?path=${encodeURIComponent(path)}`, {
      method: 'DELETE',
    });
  }

  async move(source: string, destination: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/move`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
    });
  }

  async copy(source: string, destination: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/copy`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
    });
  }

  async createDirectory(path: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/mkdir?path=${encodeURIComponent(path)}`, {
      method: 'POST',
    });
  }

  downloadUrl(path: string): string {
    return `${this.baseUrl}/download?path=${encodeURIComponent(path)}`;
  }

  private async request<T>(url: string, init?: RequestInit): Promise<T> {
    const res = await fetch(url, init);
    if (!res.ok) {
      throw new Error(res.status + ': ' + (await res.text()));
    }
    return (await res.json()) as T;
  }
}

